#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int compareDesc(const void *a, const void *b) {
    return (*(int*)b - *(int*)a);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int *motu = (int*)malloc((N / 2 + N % 2) * sizeof(int));
        int *tomu = (int*)malloc(N / 2 * sizeof(int));
        int m = 0, t = 0;
        for (int i = 0; i < N; i++) {
            if (i % 2 == 0) {
                motu[m++] = A[i];
            } else {
                tomu[t++] = A[i];
            }
        }
        qsort(motu, m, sizeof(int), compareDesc);
        qsort(tomu, t, sizeof(int), compare);
        for (int i = 0; i < t && K > 0; i++) {
            if (tomu[i] < motu[i]) {
                int temp = tomu[i];
                tomu[i] = motu[i];
                motu[i] = temp;
                K--;
            }
        }
        int motuSum = 0, tomuSum = 0;
        for (int i = 0; i < m; i++) {
            motuSum += motu[i];
        }
        for (int i = 0; i < t; i++) {
            tomuSum += tomu[i];
        }
        if (tomuSum > motuSum) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
        free(A);
        free(motu);
        free(tomu);
    }
    return 0;
}

