import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int[] motu = new int[N / 2 + N % 2];
            int[] tomu = new int[N / 2];
            int m = 0, t = 0;
            for (int i = 0; i < N; i++) {
                if (i % 2 == 0) {
                    motu[m++] = A[i];
                } else {
                    tomu[t++] = A[i];
                }
            }
            Arrays.sort(motu);
            Arrays.sort(tomu);
            for (int i = 0; i < t && K > 0; i++) {
                if (tomu[i] < motu[i]) {
                    int temp = tomu[i];
                    tomu[i] = motu[i];
                    motu[i] = temp;
                    K--;
                }
            }
            int motuSum = 0, tomuSum = 0;
            for (int i = 0; i < m; i++) {
                motuSum += motu[i];
            }
            for (int i = 0; i < t; i++) {
                tomuSum += tomu[i];
            }
            if (tomuSum > motuSum) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }
    }
}

