const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextLine() {
    return lines[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextInts() {
    return nextLine().split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let [N, K] = nextInts();
    let A = nextInts();
    let motu = [];
    let tomu = [];
    for (let i = 0; i < N; i++) {
        if (i % 2 == 0) {
            motu.push(A[i]);
        } else {
            tomu.push(A[i]);
        }
    }
    motu.sort((a, b) => b - a);
    tomu.sort((a, b) => a - b);
    for (let i = 0; i < Math.min(tomu.length, motu.length) && K > 0; i++) {
        if (tomu[i] < motu[i]) {
            [tomu[i], motu[i]] = [motu[i], tomu[i]];
            K--;
        }
    }
    let motuSum = motu.reduce((a, b) => a + b, 0);
    let tomuSum = tomu.reduce((a, b) => a + b, 0);
    if (tomuSum > motuSum) {
        console.log('YES');
    } else {
        console.log('NO');
    }
}
